const onWebSocketMsg = (data) => {
/**
 * 监听地图消息
 */

console.log(data, '主体容器模块接收到WebSocket消息---------------')
// if(data){
//   global.isMapLoaded = true;
//   rootData.rootSocket.emit(
//     // 固定的消息名称，不能修改
//     'message',
//     {
//       // 键名不能改 房间号，这里为默认值，一般无需修改，如果变量名称自己定义的则需要修改
//       room: global.socketRoom,
//       // 键名不能改 消息名称
//       type: "changeCommonParams",
//       // 键名不能改 消息内容 对象格式
//       data: {
//         selected: 'REGION_CODE',
//         REGION_CODE: global.regionaQuery.regionCode,
//       },
//     }
//   );
// }

if (Array.isArray(data) && data.length) {
  const msg = data[0];
  // 若地图加载完成
  if (msg.shareCode === 'showOldViewDialog') {
    //老大屏企业详情弹窗
    global.oldViewDialog = true;
    setTimeout(() => {
      rootData.rootSocket.emit('message', {
        room: global.socketRoom, // 房间号
        type: 'showOldViewDialog', // 消息名称
        data: msg.runtimeValue,
      });
    });
  } else if (msg.shareCode === 'showLegoDialog') {
    console.log('showLegoDialog0000000000000000000000000001')
    // 显示lego里的断面弹框
    global.businessDialog.dialogParmas = data[2].runtimeValue;
    // global.businessDialog.dialogName = data[1].runtimeValue;

    // 暂时没有修改的弹窗还用之前的方式展示
    const dialogNameList = ["waterDialogSmallWatershedComponent", 'waterDialogLivestockBreedingComponent', 'waterEnterpriseDialogComponent']
    if (dialogNameList.includes(data[1].runtimeValue)) {
      global.businessDialog.dialogName = data[1].runtimeValue;
    } else if (data[1].runtimeValue === 'videoSurveillanceComponent' && data[2].runtimeValue.datasource === 'city') {
      // 视频监控（海康）
      createDialogComponent({
        headerComName: '',
        contentComName: 'videoSurveillanceHkComponent',
        maxWidth: '1600px',
        maxHeight: '997px',
        minWidth: '1000px',
        minHeight: '720px',
        title: data.data?.dialogParams?.POINT_NAME || data[2].runtimeValue?.device_name,
      })
    } else {
      createDialogComponent({
        headerComName: '',
        contentComName: `${data[1].runtimeValue}`,
        maxWidth: '1600px',
        maxHeight: '997px',
        minWidth: '1000px',
        minHeight: '720px',
        title: data.data?.dialogParams?.POINT_NAME || data[2].runtimeValue?.device_name,
      })
    }
  } else if (msg.shareCode === 'hideLegoDialog') {
    // 关闭lego里的弹窗
    global.businessDialog.dialogName = '';
  }
}

};
const handleDialogNameChange = (params,dialogName) => {
// 展示综合查询的弹窗
global.integratedQuery.dialogName = dialogName;

setTimeout(() => {
  rootData.rootSocket.emit('message', {
      room: global.socketRoom, // 房间号
      type: 'updateDialogParams', // 消息名称
      data: {
        name: dialogName,
        params,
      },
    });
});
};
const watchIntegratedQueryVisible = () => {
// 监听综合查询的显示状态
watch(() => [global.integratedQuery.showIntegratedQuery], () => {
  // 右侧面板
  const rightDom = document.getElementById('t-component-39c5.147ea931d');
  // 综合查询
  const integratedQueryDom = document.getElementById('t-component-33a6.bb6e259b7');
  
  if (global.integratedQuery.showIntegratedQuery) {
    // 显示综合查询
    if (rightDom) {
      rightDom.style.display = 'none';
    }
    if (integratedQueryDom) {
      integratedQueryDom.style.width = '508px';
    }
  } else {
    // 显示右侧面板
    if (rightDom && global.navMenuItemActive.label !== '首页') {
      rightDom.style.display = 'block';
    }
    if (integratedQueryDom) {
      integratedQueryDom.style.width = 0;
      // integratedQueryDom.style['pointer-events'] = 'none';
    }
  }
  
  // 看下是否能从路由上获取是否隐藏头部
  const isHiddenHeader = getUrlParamValue('isHiddenHeader');
  // 如果需要隐藏头部，就得把页面变量搞出来控制这个页面的综合查询了
  state.isShowZhcxOpenBtn = !!isHiddenHeader && global.integratedQuery.showIntegratedQuery;
  state.isShowZhcxCloseBtn = !!isHiddenHeader && !global.integratedQuery.showIntegratedQuery;
}, {
  deep: true, // 深度监听
  immediate: true,
});
};
