if (data && Array.isArray(data.data) ) {
  const msg = data.data[0];
  // 若是触发点击事件
  if (msg.shareCode === 'trig_button_click') {
        /* 发送webSocket消息 */
        if (rootData?.sendMessage) {
          rootData?.sendMessage({
            id: global.socketRoom, // 房间号
