const handleAlarmMessage = () => {
async function getData() {
  if (!global.airGlobalVariables.alarmMessage.showDialog) {
    await apiRegistry.getFireList.request();
    await apiRegistry.getPointList.request();
    await apiRegistry.getRaderList.request();
    if (global.airGlobalVariables.alarmMessage.pointList.length || global.airGlobalVariables.alarmMessage.fireList.length || global.airGlobalVariables.alarmMessage.raderList.length) {
      global.airGlobalVariables.alarmMessage.showDialog = true
    }
  }
}
state.intervalId = setInterval(async () => {
  try {
    await getData();
  } catch (err) {
    console.error('轮询出错:', err);
  }
}, global.airGlobalVariables.alarmMessage.openInterval * 1000); // 每分钟执行
};
